with orders as (
    select * from {{ ref('stg_orders') }}
),

input.new_string:
-- Dedupe to the order grain: the ADF COPY loads append, so ORDERS_HEADER can carry
-- the same ORDER_NUMBER more than once. The mart contract is one row per order, so
-- keep the latest header per order_number (the staging views stay faithful passthroughs;
-- the grain is enforced here).
with orders as (
    select * from {{ ref('stg_orders') }}
    qualify row_number() over (partition by order_number order by order_ts desc) = 1
),

